package main

import (
	"context"
	"os"
	"os/exec"
	"path/filepath"
	"strings"
	"testing"
	"time"
)

func TestGeneratedHeadersCheck(t *testing.T) {
	tests := []struct {
		name   string
		files  map[string]string
		wantOK bool
		want   []string
	}{
		{
			name: "valid generated headers",
			files: map[string]string{
				"api/openapi.gen.go":                       "// Code generated by oapi-codegen; DO NOT EDIT.\n\npackage api\n",
				"internal/persistence/ent/client.go":       "// Code generated by ent, DO NOT EDIT.\n\npackage ent\n",
				"internal/persistence/ent/schema/alert.go": "package schema\n",
				"internal/persistence/ent/generate.go":     "package ent\n",
				"web/src/lib/api/openapi.ts":               "/**\n * This file was auto-generated by openapi-typescript.\n * Do not make direct changes to the file.\n */\n",
			},
			wantOK: true,
			want:   []string{"[generated-headers] OK"},
		},
		{
			name: "missing openapi go header",
			files: map[string]string{
				"api/openapi.gen.go": "package api\n",
			},
			want: []string{
				"api/openapi.gen.go missing expected generated header",
				"Code generated by oapi-codegen",
			},
		},
		{
			name: "missing ent header",
			files: map[string]string{
				"internal/persistence/ent/client.go": "package ent\n",
			},
			want: []string{
				"internal/persistence/ent/client.go missing expected generated header",
				"Code generated by ent",
			},
		},
		{
			name: "missing typescript generated marker",
			files: map[string]string{
				"web/src/lib/api/openapi.ts": "/**\n * hand written\n */\n",
			},
			want: []string{
				"web/src/lib/api/openapi.ts missing expected generated marker",
				"openapi-typescript",
			},
		},
		{
			name:   "no generated files",
			files:  map[string]string{"README.md": "# test\n"},
			wantOK: true,
			want:   []string{"no generated files found; skipping"},
		},
	}

	for _, tc := range tests {
		t.Run(tc.name, func(t *testing.T) {
			root := newGeneratedHeadersRepo(t, tc.files)

			out, err := runGeneratedHeadersCheck(t, root)
			if tc.wantOK && err != nil {
				t.Fatalf("generated header check failed: %v\n%s", err, out)
			}
			if !tc.wantOK && err == nil {
				t.Fatalf("generated header check passed unexpectedly:\n%s", out)
			}
			for _, want := range tc.want {
				if !strings.Contains(out, want) {
					t.Fatalf("generated header output = %q, want substring %q", out, want)
				}
			}
		})
	}
}

func newGeneratedHeadersRepo(t *testing.T, files map[string]string) string {
	t.Helper()

	root := t.TempDir()
	generatedHeaderWriteFile(t, root, "scripts/check_generated_headers.sh", generatedHeadersScript(t), 0o750)
	for name, body := range files {
		generatedHeaderWriteFile(t, root, name, body, 0o644)
	}
	return root
}

func generatedHeadersScript(t *testing.T) string {
	t.Helper()
	raw, err := os.ReadFile("check_generated_headers.sh")
	if err != nil {
		t.Fatalf("read generated headers script: %v", err)
	}
	return string(raw)
}

func generatedHeaderWriteFile(t *testing.T, root, name, body string, mode os.FileMode) {
	t.Helper()
	path := filepath.Join(root, filepath.FromSlash(name))
	if err := os.MkdirAll(filepath.Dir(path), 0o750); err != nil {
		t.Fatalf("mkdir %s: %v", filepath.Dir(path), err)
	}
	if err := os.WriteFile(path, []byte(body), mode); err != nil {
		t.Fatalf("write %s: %v", path, err)
	}
}

func runGeneratedHeadersCheck(t *testing.T, root string) (string, error) {
	t.Helper()
	ctx, cancel := context.WithTimeout(context.Background(), 10*time.Second)
	defer cancel()
	cmd := exec.CommandContext(ctx, "bash", "scripts/check_generated_headers.sh")
	cmd.Dir = root
	raw, err := cmd.CombinedOutput()
	return string(raw), err
}
